import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { PreferencesRepository } from '../../src/repositories/preferences.repository.js';
import {
  PreferencesService,
  resetPreferencesIdCounter,
} from '../../src/services/preferences.service.js';
import { EventBus } from '../../src/events/event-bus.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import { EmailAdapter } from '../../src/adapters/email.adapter.js';
import type { OrderCreatedEvent, UserCreatedEvent } from '../../src/events/event-types.js';

describe('PreferencesService', () => {
  let db: Database;
  let repository: PreferencesRepository;
  let service: PreferencesService;

  beforeEach(() => {
    db = new Database();
    repository = new PreferencesRepository(db);
    service = new PreferencesService(repository);
    resetPreferencesIdCounter();
  });

  describe('createForUser', () => {
    it('should create default preferences for a user', () => {
      const prefs = service.createForUser('user-1');

      expect(prefs.userId).toBe('user-1');
      expect(prefs.emailEnabled).toBe(true);
      expect(prefs.emailFrequency).toBe('immediate');
      expect(prefs.subscribedCategories).toEqual([
        'order_confirmation',
        'order_status_update',
        'welcome',
        'account_updated',
      ]);
      expect(prefs.id).toBe('pref-0001');
    });

    it('should create preferences with custom input', () => {
      const prefs = service.createForUser('user-1', {
        emailEnabled: false,
        emailFrequency: 'daily_digest',
        subscribedCategories: ['order_confirmation'],
      });

      expect(prefs.emailEnabled).toBe(false);
      expect(prefs.emailFrequency).toBe('daily_digest');
      expect(prefs.subscribedCategories).toEqual(['order_confirmation']);
    });

    it('should throw when preferences already exist for user', () => {
      service.createForUser('user-1');

      expect(() => service.createForUser('user-1')).toThrow(
        'Preferences already exist for user: user-1',
      );
    });

    it('should generate sequential IDs', () => {
      const p1 = service.createForUser('user-1');
      const p2 = service.createForUser('user-2');

      expect(p1.id).toBe('pref-0001');
      expect(p2.id).toBe('pref-0002');
    });
  });

  describe('getByUserId', () => {
    it('should return undefined when no preferences exist', () => {
      expect(service.getByUserId('user-1')).toBeUndefined();
    });

    it('should return existing preferences', () => {
      service.createForUser('user-1');
      const prefs = service.getByUserId('user-1');

      expect(prefs).toBeDefined();
      expect(prefs!.userId).toBe('user-1');
    });
  });

  describe('getOrCreateForUser', () => {
    it('should create preferences if none exist', () => {
      const prefs = service.getOrCreateForUser('user-1');

      expect(prefs.userId).toBe('user-1');
      expect(prefs.emailEnabled).toBe(true);
    });

    it('should return existing preferences without creating new ones', () => {
      service.createForUser('user-1', { emailEnabled: false });
      const prefs = service.getOrCreateForUser('user-1');

      expect(prefs.emailEnabled).toBe(false);
    });
  });

  describe('updateForUser', () => {
    it('should update emailEnabled', () => {
      service.createForUser('user-1');
      const updated = service.updateForUser('user-1', { emailEnabled: false });

      expect(updated.emailEnabled).toBe(false);
    });

    it('should update emailFrequency', () => {
      service.createForUser('user-1');
      const updated = service.updateForUser('user-1', {
        emailFrequency: 'weekly_digest',
      });

      expect(updated.emailFrequency).toBe('weekly_digest');
    });

    it('should update subscribedCategories', () => {
      service.createForUser('user-1');
      const updated = service.updateForUser('user-1', {
        subscribedCategories: ['welcome'],
      });

      expect(updated.subscribedCategories).toEqual(['welcome']);
    });

    it('should throw when no preferences exist for user', () => {
      expect(() =>
        service.updateForUser('user-1', { emailEnabled: false }),
      ).toThrow('No preferences found for user: user-1');
    });

    it('should update updatedAt timestamp', () => {
      const created = service.createForUser('user-1');
      const createdTime = created.updatedAt.getTime();

      const updated = service.updateForUser('user-1', { emailEnabled: false });

      expect(updated.updatedAt.getTime()).toBeGreaterThanOrEqual(createdTime);
    });
  });

  describe('shouldSendEmail', () => {
    it('should return true when no preferences exist (default opt-in)', () => {
      expect(service.shouldSendEmail('user-1', 'order_confirmation')).toBe(true);
    });

    it('should return true when email is enabled and category is subscribed', () => {
      service.createForUser('user-1');
      expect(service.shouldSendEmail('user-1', 'order_confirmation')).toBe(true);
    });

    it('should return false when email is disabled', () => {
      service.createForUser('user-1', { emailEnabled: false });
      expect(service.shouldSendEmail('user-1', 'order_confirmation')).toBe(false);
    });

    it('should return false when category is not subscribed', () => {
      service.createForUser('user-1', {
        subscribedCategories: ['welcome'],
      });

      expect(service.shouldSendEmail('user-1', 'order_confirmation')).toBe(false);
      expect(service.shouldSendEmail('user-1', 'welcome')).toBe(true);
    });

    it('should return false when email disabled even if category subscribed', () => {
      service.createForUser('user-1', {
        emailEnabled: false,
        subscribedCategories: ['order_confirmation'],
      });

      expect(service.shouldSendEmail('user-1', 'order_confirmation')).toBe(false);
    });
  });

  describe('getEmailFrequency', () => {
    it('should return immediate when no preferences exist', () => {
      expect(service.getEmailFrequency('user-1')).toBe('immediate');
    });

    it('should return configured frequency', () => {
      service.createForUser('user-1', { emailFrequency: 'daily_digest' });
      expect(service.getEmailFrequency('user-1')).toBe('daily_digest');
    });
  });

  describe('subscribeToCategory', () => {
    it('should add a category to subscriptions', () => {
      service.createForUser('user-1', { subscribedCategories: [] });
      const updated = service.subscribeToCategory('user-1', 'welcome');

      expect(updated.subscribedCategories).toContain('welcome');
    });

    it('should be idempotent for already subscribed categories', () => {
      service.createForUser('user-1');
      const prefs = service.subscribeToCategory('user-1', 'welcome');

      const count = prefs.subscribedCategories.filter(
        (c) => c === 'welcome',
      ).length;
      expect(count).toBe(1);
    });

    it('should create preferences if none exist', () => {
      const updated = service.subscribeToCategory('user-1', 'welcome');

      expect(updated.userId).toBe('user-1');
      expect(updated.subscribedCategories).toContain('welcome');
    });
  });

  describe('unsubscribeFromCategory', () => {
    it('should remove a category from subscriptions', () => {
      service.createForUser('user-1');
      const updated = service.unsubscribeFromCategory(
        'user-1',
        'order_confirmation',
      );

      expect(updated.subscribedCategories).not.toContain('order_confirmation');
    });

    it('should be idempotent for already unsubscribed categories', () => {
      service.createForUser('user-1', { subscribedCategories: [] });
      const prefs = service.unsubscribeFromCategory(
        'user-1',
        'order_confirmation',
      );

      expect(prefs.subscribedCategories).toEqual([]);
    });
  });

  describe('getAvailableCategories', () => {
    it('should return all notification categories', () => {
      const categories = service.getAvailableCategories();

      expect(categories).toEqual([
        'order_confirmation',
        'order_status_update',
        'welcome',
        'account_updated',
      ]);
    });

    it('should return a copy (not the original array)', () => {
      const a = service.getAvailableCategories();
      const b = service.getAvailableCategories();

      expect(a).not.toBe(b);
      expect(a).toEqual(b);
    });
  });
});

describe('NotificationService with preferences', () => {
  let db: Database;
  let repository: PreferencesRepository;
  let preferencesService: PreferencesService;
  let eventBus: EventBus;
  let notificationService: NotificationService;
  let emailAdapter: EmailAdapter;

  beforeEach(() => {
    db = new Database();
    repository = new PreferencesRepository(db);
    preferencesService = new PreferencesService(repository);
    eventBus = new EventBus();
    notificationService = new NotificationService(eventBus);
    emailAdapter = new EmailAdapter();
    notificationService.registerAdapter(emailAdapter);
    notificationService.setPreferencesService(preferencesService);
    resetNotificationIdCounter();
    resetPreferencesIdCounter();
  });

  const makeOrderCreatedEvent = (): OrderCreatedEvent => ({
    type: 'order:created',
    order: {
      id: 'order-1',
      userId: 'user-1',
      items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
      total: 10,
      status: 'pending',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    user: {
      id: 'user-1',
      name: 'Alice',
      email: 'alice@example.com',
      role: 'member',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    timestamp: new Date(),
  });

  const makeUserCreatedEvent = (): UserCreatedEvent => ({
    type: 'user:created',
    user: {
      id: 'user-1',
      name: 'Alice',
      email: 'alice@example.com',
      role: 'member',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    timestamp: new Date(),
  });

  it('should send notification when user has no preferences (default opt-in)', async () => {
    await eventBus.emit(makeOrderCreatedEvent());

    expect(notificationService.getNotificationCount()).toBe(1);
    expect(emailAdapter.getSentEmails()).toHaveLength(1);
  });

  it('should send notification when user preferences allow it', async () => {
    preferencesService.createForUser('user-1', {
      emailEnabled: true,
      subscribedCategories: ['order_confirmation'],
    });

    await eventBus.emit(makeOrderCreatedEvent());

    expect(notificationService.getNotificationCount()).toBe(1);
  });

  it('should suppress notification when email is disabled', async () => {
    preferencesService.createForUser('user-1', { emailEnabled: false });

    await eventBus.emit(makeOrderCreatedEvent());

    expect(notificationService.getNotificationCount()).toBe(0);
    expect(emailAdapter.getSentEmails()).toHaveLength(0);
  });

  it('should suppress notification when category is not subscribed', async () => {
    preferencesService.createForUser('user-1', {
      subscribedCategories: ['welcome'],
    });

    await eventBus.emit(makeOrderCreatedEvent());

    expect(notificationService.getNotificationCount()).toBe(0);
  });

  it('should allow welcome but suppress order for selective subscriptions', async () => {
    preferencesService.createForUser('user-1', {
      subscribedCategories: ['welcome'],
    });

    await eventBus.emit(makeUserCreatedEvent());
    await eventBus.emit(makeOrderCreatedEvent());

    const records = notificationService.getNotificationRecords();
    expect(records).toHaveLength(1);
    expect(records[0]?.payload.type).toBe('welcome');
  });

  it('should work without preferences service (backwards-compatible)', async () => {
    const bus = new EventBus();
    const svc = new NotificationService(bus);
    svc.registerAdapter(new EmailAdapter());

    await bus.emit(makeOrderCreatedEvent());

    expect(svc.getNotificationCount()).toBe(1);
  });
});

