diff --git a/src/services/preferences.service.ts b/src/services/preferences.service.ts
new file mode 100644
index 0000000..e8fb00f
--- /dev/null
+++ b/src/services/preferences.service.ts
@@ -0,0 +1,181 @@
+/**
+ * Preferences service — manages user notification preferences.
+ *
+ * Provides CRUD operations for user notification preferences and
+ * a query method used by NotificationService to check whether a
+ * notification should be delivered.
+ *
+ * Depends on:
+ * - PreferencesRepository for data access
+ */
+
+import type { PreferencesRepository } from '../repositories/preferences.repository.js';
+import type {
+  UserPreferences,
+  CreateUserPreferencesInput,
+  UpdateUserPreferencesInput,
+} from '../models/user-preferences.js';
+import type { NotificationType } from '../models/notification.js';
+import { ALL_NOTIFICATION_CATEGORIES, DEFAULT_PREFERENCES } from '../models/user-preferences.js';
+import { Logger } from '../utils/logger.js';
+
+let nextId = 1;
+
+function generatePreferencesId(): string {
+  return `pref-${String(nextId++).padStart(4, '0')}`;
+}
+
+/** Reset the ID counter. Useful for testing. */
+export function resetPreferencesIdCounter(): void {
+  nextId = 1;
+}
+
+export class PreferencesService {
+  private logger = new Logger('PreferencesService');
+
+  constructor(private repository: PreferencesRepository) {}
+
+  /**
+   * Get preferences for a user. Returns undefined if none exist.
+   */
+  getByUserId(userId: string): UserPreferences | undefined {
+    return this.repository.findByUserId(userId);
+  }
+
+  /**
+   * Get preferences for a user, creating defaults if none exist.
+   */
+  getOrCreateForUser(userId: string): UserPreferences {
+    const existing = this.repository.findByUserId(userId);
+    if (existing) {
+      return existing;
+    }
+    return this.createForUser(userId);
+  }
+
+  /**
+   * Create default preferences for a user.
+   */
+  createForUser(userId: string, input?: CreateUserPreferencesInput): UserPreferences {
+    const existing = this.repository.findByUserId(userId);
+    if (existing) {
+      throw new Error(`Preferences already exist for user: ${userId}`);
+    }
+
+    const now = new Date();
+    const prefs: UserPreferences = {
+      id: generatePreferencesId(),
+      userId,
+      emailEnabled: input?.emailEnabled ?? DEFAULT_PREFERENCES.emailEnabled,
+      emailFrequency: input?.emailFrequency ?? DEFAULT_PREFERENCES.emailFrequency,
+      subscribedCategories: input?.subscribedCategories ?? [...DEFAULT_PREFERENCES.subscribedCategories],
+      createdAt: now,
+      updatedAt: now,
+    };
+
+    this.repository.save(prefs);
+    this.logger.info(`Created preferences for user: ${userId}`);
+    return prefs;
+  }
+
+  /**
+   * Update a user's notification preferences.
+   */
+  updateForUser(userId: string, input: UpdateUserPreferencesInput): UserPreferences {
+    const existing = this.repository.findByUserId(userId);
+    if (!existing) {
+      throw new Error(`No preferences found for user: ${userId}`);
+    }
+
+    const updates: Partial<UserPreferences> = { updatedAt: new Date() };
+
+    if (input.emailEnabled !== undefined) {
+      updates.emailEnabled = input.emailEnabled;
+    }
+    if (input.emailFrequency !== undefined) {
+      updates.emailFrequency = input.emailFrequency;
+    }
+    if (input.subscribedCategories !== undefined) {
+      updates.subscribedCategories = input.subscribedCategories;
+    }
+
+    const updated = this.repository.update(existing.id, updates);
+    this.logger.info(`Updated preferences for user: ${userId}`);
+    return updated;
+  }
+
+  /**
+   * Check whether a notification of the given type should be delivered
+   * to the given user via email.
+   *
+   * Returns true (allow delivery) when:
+   * - No preferences record exists (default is opted-in)
+   * - emailEnabled is true AND the category is in subscribedCategories
+   *
+   * Returns false when:
+   * - emailEnabled is false
+   * - The notification type is not in subscribedCategories
+   */
+  shouldSendEmail(userId: string, notificationType: NotificationType): boolean {
+    const prefs = this.repository.findByUserId(userId);
+
+    // No preferences record → default to allowing all notifications
+    if (!prefs) {
+      return true;
+    }
+
+    if (!prefs.emailEnabled) {
+      return false;
+    }
+
+    return prefs.subscribedCategories.includes(notificationType);
+  }
+
+  /**
+   * Get the email frequency setting for a user.
+   * Returns 'immediate' if no preferences exist.
+   */
+  getEmailFrequency(userId: string): UserPreferences['emailFrequency'] {
+    const prefs = this.repository.findByUserId(userId);
+    return prefs?.emailFrequency ?? DEFAULT_PREFERENCES.emailFrequency;
+  }
+
+  /**
+   * Subscribe a user to a notification category.
+   */
+  subscribeToCategory(userId: string, category: NotificationType): UserPreferences {
+    const prefs = this.getOrCreateForUser(userId);
+
+    if (prefs.subscribedCategories.includes(category)) {
+      return prefs;
+    }
+
+    return this.repository.update(prefs.id, {
+      subscribedCategories: [...prefs.subscribedCategories, category],
+      updatedAt: new Date(),
+    });
+  }
+
+  /**
+   * Unsubscribe a user from a notification category.
+   */
+  unsubscribeFromCategory(userId: string, category: NotificationType): UserPreferences {
+    const prefs = this.getOrCreateForUser(userId);
+
+    if (!prefs.subscribedCategories.includes(category)) {
+      return prefs;
+    }
+
+    return this.repository.update(prefs.id, {
+      subscribedCategories: prefs.subscribedCategories.filter((c) => c !== category),
+      updatedAt: new Date(),
+    });
+  }
+
+  /**
+   * Get all available notification categories.
+   */
+  getAvailableCategories(): NotificationType[] {
+    return [...ALL_NOTIFICATION_CATEGORIES];
+  }
+}

